//! In-memory store for one-time enrollment tokens.
//!
//! Tokens are generated by the webapp enrollment-string endpoint and consumed
//! by the agent enrollment endpoint. Each token is single-use and has an expiry.

use std::time::{SystemTime, UNIX_EPOCH};

use dashmap::DashMap;

/// Default token lifetime if not specified: 1 hour.
const DEFAULT_TOKEN_LIFETIME_SECS: u64 = 3600;

/// A single enrollment token entry.
#[derive(Debug, Clone)]
pub struct EnrollmentTokenEntry {
    /// When this token expires (UNIX timestamp in seconds).
    pub expires_at: u64,
    /// Optional agent name hint associated with this token.
    pub agent_name: Option<String>,
}

/// Thread-safe in-memory store for one-time enrollment tokens.
///
/// Tokens are stored in a `DashMap` keyed by the token string.
/// They are removed on consumption (one-time use) or on explicit cleanup.
#[derive(Debug)]
pub struct EnrollmentTokenStore {
    tokens: DashMap<String, EnrollmentTokenEntry>,
}

impl EnrollmentTokenStore {
    /// Creates a new, empty token store.
    pub fn new() -> Self {
        Self { tokens: DashMap::new() }
    }

    /// Inserts a new enrollment token.
    ///
    /// Also cleans up any expired tokens to prevent unbounded growth.
    pub fn insert(&self, token: String, agent_name: Option<String>, lifetime_secs: Option<u64>) {
        self.cleanup_expired();

        let lifetime = lifetime_secs.unwrap_or(DEFAULT_TOKEN_LIFETIME_SECS);
        let now = current_time_secs();
        let expires_at = now + lifetime;

        self.tokens
            .insert(token, EnrollmentTokenEntry { expires_at, agent_name });
    }

    /// Consumes a token if it exists and is not expired.
    ///
    /// Returns `true` if the token was valid and has been consumed (removed).
    /// Returns `false` if the token doesn't exist or is expired.
    pub fn consume(&self, token: &str) -> bool {
        let now = current_time_secs();

        if let Some((_, entry)) = self.tokens.remove(token)
            && entry.expires_at > now
        {
            return true;
        }

        false
    }

    /// Removes all expired tokens from the store.
    pub fn cleanup_expired(&self) {
        let now = current_time_secs();
        self.tokens.retain(|_, entry| entry.expires_at > now);
    }
}

impl Default for EnrollmentTokenStore {
    fn default() -> Self {
        Self::new()
    }
}

fn current_time_secs() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn insert_and_consume() {
        let store = EnrollmentTokenStore::new();
        store.insert("tok-123".to_owned(), Some("my-agent".to_owned()), Some(3600));

        assert!(store.consume("tok-123"));
        // Second consume should fail (one-time use).
        assert!(!store.consume("tok-123"));
    }

    #[test]
    fn consume_nonexistent_returns_false() {
        let store = EnrollmentTokenStore::new();
        assert!(!store.consume("does-not-exist"));
    }

    #[test]
    fn expired_token_not_consumable() {
        let store = EnrollmentTokenStore::new();
        // Insert with 0 lifetime → already expired.
        store.insert("expired-tok".to_owned(), None, Some(0));
        assert!(!store.consume("expired-tok"));
    }

    #[test]
    fn cleanup_removes_expired() {
        let store = EnrollmentTokenStore::new();
        store.insert("expired".to_owned(), None, Some(0));
        store.insert("valid".to_owned(), None, Some(3600));

        store.cleanup_expired();

        assert!(!store.consume("expired"));
        assert!(store.consume("valid"));
    }
}
